mapper.select:
select pers_nombre from administracion.persona p
inner join administracion.usuario u on u.pers_id = p.pers_id
where u.usua_id = #{id}

mapper.update:
UPDATE administracion.persona
SET  pers_dni=#{dni}, pers_nombre=#{nombre}, pers_apellido_paterno=#{apellidoPaterno}, 
pers_apellido_materno=#{apellidoMaterno}
WHERE pers_id=#{idPersona};

update administracion.persona
set pers_estado=false
where pers_id=#{id}

update administracion.persona
set pers_estado=true
where pers_id=#{id}
